            aOrbiterI = (aOrbiterI + aOrbiterJ) + 0x7AD86BE2C113CEDAULL;
            aOrbiterA = (aOrbiterA ^ aOrbiterI) ^ 0x2F2A2A53E2D5D903ULL;
